code.C:
#include <stdio.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N;
        scanf("%lld", &N);
        if(N % 2 == 0) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

